features.snippet:
always @(A or B or TC) begin
  if (TC == 1'b0)
    PRODUCT = A * B;
  else begin
    A2 = A[A_width-1] ? -A : A;
    B2 = B[B_width-1] ? -B : B;
    PRODUCT2 = A2 * B2;
    PRODUCT = (A[A_width-1]^B[B_width-1]) ? -PRODUCT2 : PRODUCT2;
  end
end

reg [A_width-1:0] A2;
always @(A or B or TC) begin
  if (TC == 1'b0) PRODUCT = A * B;
  else A2 = A[A_width-1] ? -A : A;
end
